INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('of', 'op', 41, 'OP', '……的；属于；由……构成', 'show belonging, material, part, or relation', 'A glass of water is on the table.', '桌上有一杯水。', '[{"w":"for","def":"for: 相关的动作或关系词","vs":"与 of 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"for\" / \"of\" 的替换练习"},{"w":"till","def":"till: 可帮助扩展句型的基础词","vs":"与 of 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"till\" / \"of\" 的替换练习"},{"w":"than","def":"than: 同一组 Basic English 操作词","vs":"与 of 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"than\" / \"of\" 的替换练习"}]'),
  ('till', 'op', 42, 'OP', '直到；到……为止', 'up to the time when something happens', 'Wait here till the rain is over.', '在这里等到雨停。', '[{"w":"of","def":"of: 相关的动作或关系词","vs":"与 till 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"of\" / \"till\" 的替换练习"},{"w":"than","def":"than: 可帮助扩展句型的基础词","vs":"与 till 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"than\" / \"till\" 的替换练习"},{"w":"a","def":"a: 同一组 Basic English 操作词","vs":"与 till 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"a\" / \"till\" 的替换练习"}]'),
  ('than', 'op', 43, 'OP', '比；用于比较', 'used to compare two things', 'This road is longer than that one.', '这条路比那条路长。', '[{"w":"till","def":"till: 相关的动作或关系词","vs":"与 than 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"till\" / \"than\" 的替换练习"},{"w":"a","def":"a: 可帮助扩展句型的基础词","vs":"与 than 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"a\" / \"than\" 的替换练习"},{"w":"the","def":"the: 同一组 Basic English 操作词","vs":"与 than 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"the\" / \"than\" 的替换练习"}]'),
  ('a', 'op', 44, 'OP', '一个；一件；某个', 'used before one non-specific singular thing', 'A bird is on the roof.', '屋顶上有一只鸟。', '[{"w":"than","def":"than: 相关的动作或关系词","vs":"与 a 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"than\" / \"a\" 的替换练习"},{"w":"the","def":"the: 可帮助扩展句型的基础词","vs":"与 a 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"the\" / \"a\" 的替换练习"},{"w":"all","def":"all: 同一组 Basic English 操作词","vs":"与 a 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"all\" / \"a\" 的替换练习"}]'),
  ('the', 'op', 45, 'OP', '这；那；特指的人或物', 'used before a known or particular thing', 'The door of the room is open.', '这个房间的门开着。', '[{"w":"a","def":"a: 相关的动作或关系词","vs":"与 the 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"a\" / \"the\" 的替换练习"},{"w":"all","def":"all: 可帮助扩展句型的基础词","vs":"与 the 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"all\" / \"the\" 的替换练习"},{"w":"any","def":"any: 同一组 Basic English 操作词","vs":"与 the 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"any\" / \"the\" 的替换练习"}]');
